#include <bits/stdc++.h>
using namespace std;

int n,q,f[1<<20],g[1<<20],ones[1<<20];
char s[1<<20],t[25];

void solve1(int a,int b,int c){
    int ans=0;
    for(int i=a;;i=(i-1)&a){
        if(ones[i]%2) ans-=g[i|b];
        else ans+=g[i|b];
        if(!i) break;
    }
    printf("%d\n",ans);
}

void solve2(int a,int b,int c){
    int ans=0;
    for(int i=b;;i=(i-1)&b){
        if((ones[b]-ones[i])%2) ans-=f[i|c];
        else ans+=f[i|c];
        if(!i) break;
    }
    printf("%d\n",ans);
}

void solve3(int a,int b,int c){
    int ans=0;
    for(int i=c;;i=(i-1)&c){
        ans+=s[i|b]-'0';
        if(!i) break;
    }
    printf("%d\n",ans);
}

int main(){
    scanf("%d%d",&n,&q);
    scanf("%s",s);
    for(int i=0;i<1<<n;i++){
        if(i) ones[i]=ones[i-(i&(-i))]+1;
        f[i]=g[i]=s[i]-'0';
    }
    for(int i=0;i<n;i++)
        for(int j=0;j<1<<n;j++)
            if((j>>i)&1)
                f[j]+=f[j-(1<<i)];
            else
                g[j]+=g[j+(1<<i)];
    while(q--){
        scanf("%s",t);
        reverse(t,t+n);
        int a=0,b=0,c=0;
        for(int i=0;i<n;i++)
            if(t[i]=='0') a|=1<<i;
            else if(t[i]=='1') b|=1<<i;
            else c|=1<<i;
        if(ones[a]<=ones[b] && ones[a]<=ones[c]) solve1(a,b,c);
        else if(ones[b]<=ones[a] && ones[b]<=ones[c]) solve2(a,b,c);
        else solve3(a,b,c);
    }
    return 0;
}
